     1→"use client";
     2→
     3→import { useCallback, useRef, useState } from "react";
     4→
     5→const DEEPGRAM_API_KEY = process.env.NEXT_PUBLIC_DEEPGRAM_API_KEY || "";
     6→const DEEPGRAM_WS_URL =
     7→  "wss://api.deepgram.com/v1/listen?" +
     8→  "model=nova-2&smart_format=true&interim_results=true" +
     9→  "&vad_events=true&utterance_end_ms=1500" +
    10→  "&encoding=linear16&sample_rate=16000";
    11→
    12→const MAX_RECONNECTS = 3;
    13→
    14→export interface UseDeepgramSTTReturn {
    15→  isListening: boolean;
    16→  transcript: string;
    17→  interimTranscript: string;
    18→  startListening: () => void;
    19→  stopListening: () => void;
    20→}
    21→
    22→export function useDeepgramSTT(): UseDeepgramSTTReturn {
    23→  const [isListening, setIsListening] = useState(false);
    24→  const [transcript, setTranscript] = useState("");
    25→  const [interimTranscript, setInterimTranscript] = useState("");
    26→  const wsRef = useRef<WebSocket | null>(null);
    27→  const streamRef = useRef<MediaStream | null>(null);
    28→  const audioCtxRef = useRef<AudioContext | null>(null);
    29→  const processorRef = useRef<ScriptProcessorNode | null>(null);
    30→  const resumeIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    31→  const reconnectCountRef = useRef(0);
    32→
    33→  const cleanup = useCallback(() => {
    34→    if (resumeIntervalRef.current) {
    35→      clearInterval(resumeIntervalRef.current);
    36→      resumeIntervalRef.current = null;
    37→    }
    38→    processorRef.current?.disconnect();
    39→    processorRef.current = null;
    40→    audioCtxRef.current?.close().catch(() => {});
    41→    audioCtxRef.current = null;
    42→    streamRef.current?.getTracks().forEach((t) => t.stop());
    43→    streamRef.current = null;
    44→    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
    45→      wsRef.current.close();
    46→    }
    47→    wsRef.current = null;
    48→    reconnectCountRef.current = 0;
    49→    setIsListening(false);
    50→    setInterimTranscript("");
    51→  }, []);
    52→
    53→  const connectWebSocket = useCallback(
    54→    (stream: MediaStream) => {
    55→      if (!DEEPGRAM_API_KEY) {
    56→        console.warn("[DeepgramSTT] No API key configured");
    57→        return;
    58→      }
    59→
    60→      const ws = new WebSocket(DEEPGRAM_WS_URL, ["token", DEEPGRAM_API_KEY]);
    61→      wsRef.current = ws;
    62→
    63→      ws.onopen = () => {
    64→        setIsListening(true);
    65→        reconnectCountRef.current = 0;
    66→
    67→        // Clean up old audio pipeline if reconnecting
    68→        if (resumeIntervalRef.current) {
    69→          clearInterval(resumeIntervalRef.current);
    70→          resumeIntervalRef.current = null;
    71→        }
    72→        processorRef.current?.disconnect();
    73→        audioCtxRef.current?.close().catch(() => {});
    74→
    75→        // Create fresh audio pipeline: mic → AudioContext → ScriptProcessor → WebSocket
    76→        const audioCtx = new AudioContext({ sampleRate: 16000 });
    77→        audioCtxRef.current = audioCtx;
    78→        const source = audioCtx.createMediaStreamSource(stream);
    79→        const processor = audioCtx.createScriptProcessor(4096, 1, 1);
    80→        processorRef.current = processor;
    81→
    82→        processor.onaudioprocess = (e) => {
    83→          if (ws.readyState !== WebSocket.OPEN) return;
    84→          const float32 = e.inputBuffer.getChannelData(0);
    85→          // Convert Float32 PCM to Int16 PCM
    86→          const int16 = new Int16Array(float32.length);
    87→          for (let i = 0; i < float32.length; i++) {
    88→            const s = Math.max(-1, Math.min(1, float32[i]));
    89→            int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
    90→          }
    91→          ws.send(int16.buffer);
    92→        };
    93→
    94→        source.connect(processor);
    95→        processor.connect(audioCtx.destination);
    96→
    97→        // Periodically resume AudioContext if browser suspends it (tab switch / idle)
    98→        resumeIntervalRef.current = setInterval(() => {
    99→          if (audioCtx.state === "suspended") {
   100→            audioCtx.resume().catch(() => {});
   101→          }
   102→        }, 3000);
   103→      };
